import{_ as t,o as e,c as r,a4 as a}from"./chunks/framework.CRLRfKFc.js";const S=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"S6-Go/阶段10-安全与加密.md","filePath":"S6-Go/阶段10-安全与加密.md","lastUpdated":1780660866000}'),n={name:"S6-Go/阶段10-安全与加密.md"};function s(l,o,i,g,d,c){return e(),r("div",null,[...o[0]||(o[0]=[a('<h2 id="🔐-阶段十-安全与加密" tabindex="-1">🔐 阶段十：安全与加密 <a class="header-anchor" href="#🔐-阶段十-安全与加密" aria-label="Permalink to &quot;🔐 阶段十：安全与加密&quot;">​</a></h2><h3 id="_10-1-认证与授权" tabindex="-1">10.1 认证与授权 <a class="header-anchor" href="#_10-1-认证与授权" aria-label="Permalink to &quot;10.1 认证与授权&quot;">​</a></h3><h4 id="q44-jwt-的工作原理是什么-如何安全地在-go-中使用" tabindex="-1">Q44: JWT 的工作原理是什么？如何安全地在 Go 中使用？ <a class="header-anchor" href="#q44-jwt-的工作原理是什么-如何安全地在-go-中使用" aria-label="Permalink to &quot;Q44: JWT 的工作原理是什么？如何安全地在 Go 中使用？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：🔥 高频</p><p><strong>考点</strong>：Token 结构、签名算法、无状态认证、黑名单/刷新机制。</p><p><strong>💡 记忆关键词</strong>：Header.Payload.Signature、短过期、Refresh Token、黑名单</p><p><strong>答案要点</strong>：</p><ul><li><strong>结构</strong>：Header.Payload.Signature，Base64 编码，不包含敏感信息。</li><li><strong>签名</strong>：使用 HS256（对称）或 RS256（非对称），Go 中推荐 <code>golang-jwt/jwt/v5</code>。</li><li><strong>安全实践</strong>： <ul><li>设置短过期时间（如 15 分钟），配合 Refresh Token 续期。</li><li>敏感操作需二次验证。</li><li>注销/踢人需引入 Redis 黑名单或版本号机制（JWT 本身无法主动失效）。</li></ul></li></ul><h4 id="q45-如何防止-csrf-和-xss-攻击" tabindex="-1">Q45: 如何防止 CSRF 和 XSS 攻击？ <a class="header-anchor" href="#q45-如何防止-csrf-和-xss-攻击" aria-label="Permalink to &quot;Q45: 如何防止 CSRF 和 XSS 攻击？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：同源策略、Token 校验、内容安全策略。</p><p><strong>💡 记忆关键词</strong>：SameSite、CSRF Token、输出转义、CSP</p><p><strong>答案要点</strong>：</p><ul><li><strong>CSRF</strong>：使用 <code>SameSite</code> Cookie 属性；表单提交携带自定义 Header 或 CSRF Token；验证 <code>Referer</code>/<code>Origin</code>。</li><li><strong>XSS</strong>：输出转义（Go <code>html/template</code> 默认转义）；设置 <code>Content-Security-Policy</code> (CSP) 头；避免 <code>innerHTML</code> 渲染不可信内容。</li></ul><h3 id="_10-2-数据加密" tabindex="-1">10.2 数据加密 <a class="header-anchor" href="#_10-2-数据加密" aria-label="Permalink to &quot;10.2 数据加密&quot;">​</a></h3><h4 id="q46-go-中如何实现敏感数据加密存储-如密码、身份证号" tabindex="-1">Q46: Go 中如何实现敏感数据加密存储（如密码、身份证号）？ <a class="header-anchor" href="#q46-go-中如何实现敏感数据加密存储-如密码、身份证号" aria-label="Permalink to &quot;Q46: Go 中如何实现敏感数据加密存储（如密码、身份证号）？&quot;">​</a></h4><p><strong>难度</strong>：⭐⭐⭐ | <strong>频率</strong>：📌 常考</p><p><strong>考点</strong>：哈希加盐、对称/非对称加密、密钥管理。</p><p><strong>💡 记忆关键词</strong>：bcrypt/argon2、AES-GCM、KMS、mTLS</p><p><strong>答案要点</strong>：</p><ul><li><strong>密码</strong>：使用 <code>bcrypt</code> 或 <code>argon2</code> 进行单向哈希，绝对禁止明文或 MD5/SHA1。</li><li><strong>敏感字段</strong>：使用 AES-GCM（对称加密）加密后存 DB，密钥通过 KMS（如 AWS KMS、HashiCorp Vault）管理，禁止硬编码。</li><li><strong>传输</strong>：全站 HTTPS，内部服务启用 mTLS。</li></ul><hr>',22)])])}const h=t(n,[["render",s]]);export{S as __pageData,h as default};
